// AgentRuntime is the Schema for the agentruntimes API
type AgentRuntime struct {
	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`

	Spec   AgentRuntimeSpec   `json:"spec,omitempty"`
	Status AgentRuntimeStatus `json:"status,omitempty"`
}

// AgentRuntimeSpec defines the desired state of AgentRuntime
type AgentRuntimeSpec struct {
	// TargetPort is the port on which the agent runtime listens
	TargetPort int32 `json:"targetPort"`

	// SandboxTemplate defines the template for creating sandbox pods
	SandboxTemplate SandboxTemplate `json:"sandboxTemplate"`

	// SessionTimeout is the timeout for a session (default: 15m)
	// +kubebuilder:default="15m"
	SessionTimeout string `json:"sessionTimeout,omitempty"`

	// MaxSessionDuration is the maximum duration for a session (default: 8h)
	// +kubebuilder:default="8h"
	MaxSessionDuration string `json:"maxSessionDuration,omitempty"`
}

