	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`

	Spec   CodeInterpreterSpec   `json:"spec,omitempty"`
	Status CodeInterpreterStatus `json:"status,omitempty"`
}

// CodeInterpreterSpec defines the desired state of CodeInterpreter
type CodeInterpreterSpec struct {
	// Ports are the ports exposed by the code interpreter
	Ports []TargetPort `json:"ports,omitempty"`

	// Template is the sandbox template for the code interpreter
	Template CodeInterpreterSandboxTemplate `json:"template"`

	// SessionTimeout is the timeout for a session (default: 15m)
	// +kubebuilder:default="15m"
	SessionTimeout string `json:"sessionTimeout,omitempty"`

	// MaxSessionDuration is the maximum duration for a session (default: 8h)
	// +kubebuilder:default="8h"
	MaxSessionDuration string `json:"maxSessionDuration,omitempty"`

	// WarmPoolSize is the size of the warm pool for code interpreters
	WarmPoolSize int32 `json:"warmPoolSize,omitempty"`

	// AuthMode is the authentication mode (picod or none)
	// +kubebuilder:default="picod"
	AuthMode AuthModeType `json:"authMode,omitempty"`
}

// TargetPort defines a port target
type TargetPort struct {
	// PathPrefix is the URL path prefix for this port
	PathPrefix string `json:"pathPrefix"`

	// Name is the name of the port
	Name string `json:"name"`

	// Port is the port number
	Port int32 `json:"port"`

	// Protocol is the protocol (HTTP, HTTPS, TCP)
	// +kubebuilder:default=HTTP
	Protocol ProtocolType `json:"protocol,omitempty"`
}

// AuthModeType defines the authentication mode
// +kubebuilder:validation:Enum=picod;none
type AuthModeType string

const (
	// AuthModePicod uses PicoD JWT authentication
	AuthModePicod AuthModeType = "picod"
	// AuthModeNone disables authentication
	AuthModeNone AuthModeType = "none"
)

// ProtocolType defines the protocol type
// +kubebuilder:validation:Enum=HTTP;HTTPS;TCP
type ProtocolType string

const (
	// ProtocolHTTP uses HTTP protocol
	ProtocolHTTP ProtocolType = "HTTP"
	// ProtocolHTTPS uses HTTPS protocol
	ProtocolHTTPS ProtocolType = "HTTPS"
	// ProtocolTCP uses TCP protocol
	ProtocolTCP ProtocolType = "TCP"
)

