package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type redisStore struct {
	cli                *redis.Client
	sessionPrefix      string
	expiryIndexKey     string
	lastActivityIndexKey string
}

func NewRedisStore() Store {
	cli := redis.NewClient(makeRedisOptions())
	return &redisStore{
		cli:                cli,
		sessionPrefix:      "session:",
		expiryIndexKey:     "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
}

func makeRedisOptions() *redis.Options {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")
	if passwordRequired == "true" && password == "" {
		panic("REDIS_PASSWORD is required when REDIS_PASSWORD_REQUIRED is true")
	}

	return &redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	}
}

func (s *redisStore) Ping(ctx context.Context) error {
	return s.cli.Ping(ctx).Err()
}

func (s *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionKey(sessionID)
	data, err := s.cli.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, fmt.Errorf(ErrNotFound)
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (s *redisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	key := s.sessionKey(sandbox.SessionID)
	pipe := s.cli.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, s.expiryIndexKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	pipe.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{
		Score:  float64(sandbox.CreatedAt.Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (s *redisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	key := s.sessionKey(sandbox.SessionID)
	result, err := s.cli.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !result {
		return fmt.Errorf(ErrNotFound)
	}

	return s.cli.ZAdd(ctx, s.expiryIndexKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	}).Err()
}

func (s *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)
	pipe := s.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, s.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, s.lastActivityIndexKey, sessionID)
	_, err := pipe.Exec(ctx)
	return err
}

func (s *redisStore) ListExpiredSandboxes(ctx context.Context, before int64, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.expiryIndexKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before, 10),
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) ListInactiveSandboxes(ctx context.Context, before int64, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.lastActivityIndexKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before, 10),
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)
	exists, err := s.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return fmt.Errorf(ErrNotFound)
	}

	return s.cli.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sessionID,
	}).Err()
}

func (s *redisStore) Close() error {
	return s.cli.Close()
}

func (s *redisStore) sessionKey(sessionID string) string {
	return s.sessionPrefix + sessionID
}

func (s *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionKey(id)
	}

	values, err := s.cli.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for _, val := range values {
		if val == nil {
			continue
		}

		data, ok := val.(string)
		if !ok || data == "" {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

