package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type valkeyStore struct {
	cli                *valkey.Client
	sessionPrefix      string
	expiryIndexKey     string
	lastActivityIndexKey string
}

func NewValkeyStore() Store {
	cli, err := valkey.NewClient(makeValkeyOptions())
	if err != nil {
		panic(err)
	}

	return &valkeyStore{
		cli:                cli,
		sessionPrefix:      "session:",
		expiryIndexKey:     "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
}

func makeValkeyOptions() valkey.ClientOption {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if passwordRequired == "true" && password == "" {
		panic("VALKEY_PASSWORD is required when VALKEY_PASSWORD_REQUIRED is true")
	}

	disableCache := os.Getenv("VALKEY_DISABLE_CACHE") == "true"
	forceSingle := os.Getenv("VALKEY_FORCE_SINGLE") == "true"

	clientOption := valkey.ClientOption{
		InitAddress:      []string{addr},
		Password:         password,
		DisableCache:     disableCache,
		DisableAutoPipelining: false,
	}

	if forceSingle {
		clientOption.AddressByGroup = map[string][]string{"single": {addr}}
	}

	return clientOption
}

func (s *valkeyStore) Ping(ctx context.Context) error {
	return s.cli.Do(ctx, s.cli.B().Ping()).Error()
}

func (s *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionKey(sessionID)
	data, err := s.cli.Do(ctx, s.cli.B().Get().Key(key).Build()).ToString()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, fmt.Errorf(ErrNotFound)
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (s *valkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	key := s.sessionKey(sandbox.SessionID)
	_, err = s.cli.DoMulti(
		ctx,
		s.cli.B().Set().Key(key).Value(string(data)).Build(),
		s.cli.B().Zadd().Key(s.expiryIndexKey).ScoreMember(float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID).Build(),
		s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember(float64(sandbox.CreatedAt.Unix()), sandbox.SessionID).Build(),
	)

	return err
}

func (s *valkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	key := s.sessionKey(sandbox.SessionID)
	result, err := s.cli.Do(ctx, s.cli.B().Set().Key(key).Value(string(data)).SetXX().Build()).ToString()
	if err != nil {
		return err
	}
	if result != "OK" {
		return fmt.Errorf(ErrNotFound)
	}

	return s.cli.Do(ctx, s.cli.B().Zadd().Key(s.expiryIndexKey).ScoreMember(float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID).Build()).Error()
}

func (s *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)
	_, err := s.cli.DoMulti(
		ctx,
		s.cli.B().Del().Key(key).Build(),
		s.cli.B().Zrem().Key(s.expiryIndexKey).Member(sessionID).Build(),
		s.cli.B().Zrem().Key(s.lastActivityIndexKey).Member(sessionID).Build(),
	)
	return err
}

func (s *valkeyStore) ListExpiredSandboxes(ctx context.Context, before int64, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.expiryIndexKey).Min("-inf").Max(strconv.FormatInt(before, 10)).Limit(0, int64(limit)).Build()).ToArray()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) ListInactiveSandboxes(ctx context.Context, before int64, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.lastActivityIndexKey).Min("-inf").Max(strconv.FormatInt(before, 10)).Limit(0, int64(limit)).Build()).ToArray()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)
	exists, err := s.cli.Do(ctx, s.cli.B().Exists().Key(key).Build()).AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return fmt.Errorf(ErrNotFound)
	}

	return s.cli.Do(ctx, s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember(float64(time.Now().Unix()), sessionID).Build()).Error()
}

func (s *valkeyStore) Close() error {
	return s.cli.Close()
}

func (s *valkeyStore) sessionKey(sessionID string) string {
	return s.sessionPrefix + sessionID
}

func (s *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []valkey.ValkeyString) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionKey(id.String())
	}

	values, err := s.cli.Do(ctx, s.cli.B().Mget().Key(keys...).Build()).AsStrSlice()
	if err != nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for _, val := range values {
		if val == "" {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &sandbox); err != nil {
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

