package picod

import (
	"bytes"
	"context"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
)

type ExecuteRequest struct {
	Command   string   `json:"command"`
	Args      []string `json:"args,omitempty"`
	Timeout   int      `json:"timeout,omitempty"`
	Directory string   `json:"directory,omitempty"`
	Env       []string `json:"env,omitempty"`
}

type ExecuteResponse struct {
	ExitCode int    `json:"exitCode"`
	Stdout   string `json:"stdout"`
	Stderr   string `json:"stderr"`
}

func (s *Server) ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	timeout := time.Duration(req.Timeout) * time.Second
	if timeout == 0 {
		timeout = DefaultTimeout
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	var stdout, stderr bytes.Buffer
	cmd := exec.CommandContext(ctx, req.Command, req.Args...)

	if req.Directory != "" {
		absPath, err := filepath.Abs(filepath.Join(s.workspace, req.Directory))
		if err != nil {
			c.JSON(400, gin.H{"error": fmt.Sprintf("invalid directory: %v", err)})
			return
		}

		if !strings.HasPrefix(absPath, filepath.Clean(s.workspace)) {
			c.JSON(403, gin.H{"error": "directory outside workspace"})
			return
		}

		cmd.Dir = absPath
	} else {
		cmd.Dir = s.workspace
	}

	env := os.Environ()
	for _, e := range req.Env {
		env = append(env, e)
	}
	cmd.Env = env

	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()

	resp := ExecuteResponse{
		Stdout: stdout.String(),
		Stderr: stderr.String(),
	}

	if ctx.Err() == context.DeadlineExceeded {
		resp.ExitCode = TimeoutExitCode
	} else if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			resp.ExitCode = exitErr.ExitCode()
		} else {
			resp.ExitCode = 1
		}
	} else {
		resp.ExitCode = 0
	}

	c.JSON(200, resp)
}

