package picod

import (
	"encoding/base64"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strconv"
	"strings"

	"github.com/gin-gonic/gin"
)

type FileInfo struct {
	Name string `json:"name"`
	Size int64  `json:"size"`
	Mode string `json:"mode"`
	IsDir bool   `json:"isDir"`
}

type UploadFileRequest struct {
	Content string `json:"content,omitempty"`
	Path    string `json:"path,omitempty"`
	Mode    string `json:"mode,omitempty"`
}

type FileEntry struct {
	Name  string `json:"name"`
	IsDir bool   `json:"isDir"`
	Size  int64  `json:"size,omitempty"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

func (s *Server) UploadFileHandler(c *gin.Context) {
	var req UploadFileRequest

	contentType := c.GetHeader("Content-Type")
	if strings.HasPrefix(contentType, "multipart/form-data") {
		file, header, err := c.Request.FormFile("file")
		if err != nil {
			c.JSON(400, gin.H{"error": err.Error()})
			return
		}
		defer file.Close()

		req.Path = c.PostForm("path")
		if req.Path == "" {
			req.Path = header.Filename
		}

		modeStr := c.PostForm("mode")
		if modeStr == "" {
			modeStr = strconv.FormatInt(DefaultFileMode, 8)
		}
		req.Mode = modeStr

		sanitizedPath, err := s.sanitizePath(req.Path)
		if err != nil {
			c.JSON(403, gin.H{"error": err.Error()})
			return
		}

		mode, err := parseFileMode(req.Mode)
		if err != nil {
			c.JSON(400, gin.H{"error": err.Error()})
			return
		}

		fullPath := filepath.Join(s.workspace, sanitizedPath)
		if err := os.MkdirAll(filepath.Dir(fullPath), DirectoryMode); err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}

		outFile, err := os.OpenFile(fullPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, mode)
		if err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
		defer outFile.Close()

		if _, err := io.Copy(outFile, file); err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}

		c.JSON(200, gin.H{"path": sanitizedPath})
		return
	}

	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	sanitizedPath, err := s.sanitizePath(req.Path)
	if err != nil {
		c.JSON(403, gin.H{"error": err.Error()})
		return
	}

	mode, err := parseFileMode(req.Mode)
	if err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	fullPath := filepath.Join(s.workspace, sanitizedPath)
	if err := os.MkdirAll(filepath.Dir(fullPath), DirectoryMode); err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	if req.Content != "" {
		data, err := base64.StdEncoding.DecodeString(req.Content)
		if err != nil {
			c.JSON(400, gin.H{"error": "invalid base64 content"})
			return
		}

		if err := os.WriteFile(fullPath, data, mode); err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
	}

	c.JSON(200, gin.H{"path": sanitizedPath})
}

func (s *Server) ListFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		path = "/"
	}

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(403, gin.H{"error": err.Error()})
		return
	}

	fullPath := filepath.Join(s.workspace, sanitizedPath)
	entries, err := os.ReadDir(fullPath)
	if err != nil {
		c.JSON(404, gin.H{"error": err.Error()})
		return
	}

	var files []FileEntry
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		file := FileEntry{
			Name:  entry.Name(),
			IsDir: entry.IsDir(),
		}

		if !entry.IsDir() {
			file.Size = info.Size()
		}

		files = append(files, file)
	}

	c.JSON(200, ListFilesResponse{Files: files})
}

func (s *Server) DownloadFileHandler(c *gin.Context) {
	path := c.Param("path")
	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(403, gin.H{"error": err.Error()})
		return
	}

	fullPath := filepath.Join(s.workspace, sanitizedPath)
	if _, err := os.Stat(fullPath); os.IsNotExist(err) {
		c.JSON(404, gin.H{"error": "file not found"})
		return
	}

	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%s", filepath.Base(sanitizedPath)))
	c.File(fullPath)
}

func (s *Server) sanitizePath(path string) (string, error) {
	path = filepath.Clean(path)
	if strings.HasPrefix(path, "..") || strings.Contains(path, "../") {
		return "", fmt.Errorf("invalid path: %s", path)
	}
	return path, nil
}

func parseFileMode(modeStr string) (os.FileMode, error) {
	if modeStr == "" {
		return DefaultFileMode, nil
	}

	mode, err := strconv.ParseInt(modeStr, 8, 32)
	if err != nil {
		return 0, fmt.Errorf("invalid file mode: %s", modeStr)
	}

	if mode > 0777 {
		return 0, fmt.Errorf("file mode too permissive: %s", modeStr)
	}

	return os.FileMode(mode), nil
}

func MkdirAll(path string, perm os.FileMode) error {
	return os.MkdirAll(path, perm)
}

