package picod

import (
	"fmt"
	"os"
	"time"

	"github.com/gin-gonic/gin"
)

type Server struct {
	config      Config
	engine      *gin.Engine
	authManager *AuthManager
	workspace   string
}

func NewServer(config Config) (*Server, error) {
	authManager, err := NewAuthManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create auth manager: %w", err)
	}

	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Recovery())
	engine.Use(gin.Logger())

	server := &Server{
		config:      config,
		engine:      engine,
		authManager: authManager,
		workspace:   config.Workspace,
	}

	server.setupRoutes()
	server.setWorkspace()

	return server, nil
}

func (s *Server) setupRoutes() {
	s.engine.GET("/health", s.handleHealth)

	api := s.engine.Group("/api")
	api.Use(s.authManager.AuthMiddleware())
	api.Use(s.authManager.LimitBodySize(MaxBodySize))
	{
		api.POST("/execute", s.ExecuteHandler)
		api.POST("/files", s.UploadFileHandler)
		api.GET("/files", s.ListFilesHandler)
		api.GET("/files/*path", s.DownloadFileHandler)
	}
}

func (s *Server) setWorkspace() {
	if err := os.MkdirAll(s.workspace, DirectoryMode); err != nil {
		panic(fmt.Sprintf("failed to create workspace: %v", err))
	}
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(200, gin.H{"status": "healthy"})
}

func (s *Server) Run() error {
	srv := &http.Server{
		Addr:              ":" + s.config.Port,
		Handler:           s.engine,
		ReadHeaderTimeout: 30 * time.Second,
	}

	fmt.Printf("PicoD server listening on port %s, workspace: %s\n", s.config.Port, s.workspace)
	return srv.ListenAndServe()
}

func (s *Server) setWorkspacePath(path string) {
	s.workspace = path
}

