package main

import (
	"flag"
	"os"
	"os/signal"
	"syscall"

	"github.com/volcano-sh/agentcube/pkg/picod"
)

func main() {
	port := flag.String("port", "8080", "Port to listen on")
	workspace := flag.String("workspace", "/workspace", "Workspace directory")
	flag.Parse()

	config := picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	server, err := picod.NewServer(config)
	if err != nil {
		panic(err)
	}

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigChan
		os.Exit(0)
	}()

	if err := server.Run(); err != nil {
		panic(err)
	}
}

