package agentd

import (
	"context"
	"fmt"
	"time"

	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"

	agentv1 "sigs.k8s.io/agent-sandbox/apis/sandbox/v1alpha1"
)

type Reconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&agentv1.Sandbox{}).
		Complete(r)
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	sandbox := &agentv1.Sandbox{}
	err := r.Get(ctx, req.NamespacedName, sandbox)
	if err != nil {
		if errors.IsNotFound(err) {
			return ctrl.Result{}, nil
		}
		return ctrl.Result{}, err
	}

	lastActivityStr, exists := sandbox.Annotations[LastActivityAnnotationKey]
	if !exists {
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		return reconcile.Result{RequeueAfter: 30 * time.Second}, nil
	}

	expiration := lastActivity.Add(SessionExpirationTimeout)
	now := time.Now()

	if now.After(expiration) {
		if err := r.Delete(ctx, sandbox); err != nil && !errors.IsNotFound(err) {
			return ctrl.Result{}, err
		}
		return ctrl.Result{}, nil
	}

	requeueDuration := expiration.Sub(now) + 1*time.Second
	return reconcile.Result{RequeueAfter: requeueDuration}, nil
}
